CREATE TABLE IF NOT EXISTS "account_group_rates" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "account_id" INTEGER NOT NULL, "group_key" TEXT NOT NULL, "group_name" TEXT NOT NULL, "description" TEXT, "ratio" DOUBLE PRECISION NOT NULL, "last_synced_at" TEXT NOT NULL, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("account_id") REFERENCES "accounts"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "account_group_rates_account_group_unique" ON "account_group_rates" ("account_id", "group_key");
CREATE INDEX "account_group_rates_account_id_idx" ON "account_group_rates" ("account_id");
